parameters.functionCode:
// Determine severity and extract key info
const error = $input.first().json;
const execution = error.execution;
const workflow = error.workflow;

let severity = 'low';
const errorMessage = error.message || '';
const workflowName = workflow?.name || 'Unknown';
const nodeName = error.node?.name || 'Unknown';

// Critical: payment processed but proxy not delivered
if (errorMessage.includes('provider') && errorMessage.includes('failed')) {
  severity = 'critical';
}
// High: webhook failed or provider API down
else if (errorMessage.includes('webhook') || errorMessage.includes('API')) {
  severity = 'high';
}
// Medium: timeout, rate limit
else if (errorMessage.includes('timeout') || errorMessage.includes('rate limit')) {
  severity = 'medium';
}

return [{
  json: {
    severity,
    workflowName,
    nodeName,
    errorMessage: errorMessage.substring(0, 500),
    executionId: execution?.id,
    timestamp: new Date().toISOString()
  }
}];

